const record = $input.first().json;

const postType = (record.post_type || '').toLowerCase();
const inferredStyle =
  ['news','athlete','opinion','fact'].includes(postType) ? 'twitter_card_balanced' :
  ['meme','reaction'].includes(postType) ? 'snap_overlay' :
  'product_carousel';

const templateStyle = (record.template_style || inferredStyle || 'product_carousel').toLowerCase();
const mediaSourceType = (record.media_source_type || 'product_image').toLowerCase();

const pickFirst = (...values) => values.find(v => typeof v === 'string' && v.trim() !== '');

const sourceImage = pickFirst(record.source_image_url, record.news_image_url, record.slide_1_image_url, record.image_url, record.product_image_url, record.shopify_image_url);
const articleSummary = pickFirst(record.article_summary, record.article_text_summary, record.summary_text, record.source_summary, record.description, record.source_description, record.slide_story_summary, record.caption);
const articleTitle = pickFirst(record.headline_text, record.source_title, record.title, record.slide_1_main_text);
const articleUrl = pickFirst(record.source_url, record.article_url, record.url);

const common = {
  shirt_name: record.shirt_name,
  record_id: record.id,
  post_type: postType || 'product',
  template_style: templateStyle,
  media_source_type: mediaSourceType,
  source_image_url: sourceImage,
  article_summary: articleSummary || '',
  article_title: articleTitle || '',
  article_url: articleUrl || '',
  template_uuid_twitter_card_balanced: record.template_uuid_twitter_card_balanced || 'bazsa46k83jxi',
  template_uuid_snap_overlay: record.template_uuid_snap_overlay || 'yxbgkx7gwh3dx'
};

if (templateStyle === 'twitter_card_balanced') {
  return [{ json: { ...common, slide: 1, template: 'TWITTER_CARD_BALANCED', fal_prompt: mediaSourceType === 'ai_generated' ? pickFirst(record.slide_1_fal_prompt, record.fal_prompt) : null, main_text: pickFirst(record.headline_text, record.slide_1_main_text, record.caption), sub_text: pickFirst(record.sub_text, record.slide_2_sub_text, 'mildly.outdoorsy'), brand_handle: pickFirst(record.brand_handle, 'mildly.outdoorsy'), bg_color: '#FFFFFF' } }];
}

if (templateStyle === 'snap_overlay') {
  return [{ json: { ...common, slide: 1, template: 'SNAP_OVERLAY', fal_prompt: mediaSourceType === 'ai_generated' ? pickFirst(record.slide_1_fal_prompt, record.fal_prompt) : null, main_text: pickFirst(record.caption_text, record.slide_1_main_text, record.caption), sub_text: pickFirst(record.brand_handle, 'mildly.outdoorsy'), brand_handle: pickFirst(record.brand_handle, 'mildly.outdoorsy'), bg_color: '#000000' } }];
}

const textFor = (mainText, subText) => [mainText, subText].filter(v => typeof v === 'string' && v.trim() !== '').join(' — ');

const buildStoryPrompt = (slideNum, mainText, subText) => {
  const beat = {
    2: 'Setup extension: slight environment/context reveal from slide 1.',
    3: 'Tension: introduce contrast/problem cue while keeping continuity.',
    4: 'Turning point: signal action/change/insight with subtle motion cues.',
    5: 'Resolution: calmer confident end-state, visually tied to slide 1.'
  }[slideNum] || 'Continue story progression.';

  return [
    'You are generating slide ' + slideNum + ' for a 5-slide storytelling carousel.',
    'Primary requirement: use slide 1 image as reference anchor; keep same subject identity, style, camera feel, and scene continuity.',
    'Narrative beat: ' + beat,
    'Article title: ' + (common.article_title || 'outdoor story'),
    'Article summary/context: ' + (common.article_summary || 'No summary provided; infer from slide text and title.'),
    'This slide text (must be visually represented): ' + textFor(mainText, subText),
    'At least one concrete noun from the slide text must be visible in the image composition.',
    'Mood must align with the slide text verbs/adjectives and avoid contradiction with the headline claim.',
    'Keep changes subtle (time-of-day, expression, props, motion cues, environmental detail shifts).',
    'Photorealistic editorial outdoor style. No text overlays, logos, watermarks.'
  ].join(' ');
};

return [
  { json: { ...common, slide: 1, template: 'A', fal_prompt: null, main_text: record.slide_1_main_text, sub_text: record.slide_1_sub_text, bg_color: null, reference_image_url: common.source_image_url } },
  { json: { ...common, slide: 2, template: 'B', fal_prompt: pickFirst(record.slide_2_fal_prompt, buildStoryPrompt(2, record.slide_2_main_text, record.slide_2_sub_text)), main_text: record.slide_2_main_text, sub_text: record.slide_2_sub_text, bg_color: record.slide_2_bg_color, reference_image_url: common.source_image_url, reference_strength: 0.82, creativity_strength: 0.28 } },
  { json: { ...common, slide: 3, template: 'A', fal_prompt: pickFirst(record.slide_3_fal_prompt, buildStoryPrompt(3, record.slide_3_main_text, record.slide_3_sub_text)), main_text: record.slide_3_main_text, sub_text: record.slide_3_sub_text, bg_color: null, reference_image_url: common.source_image_url, reference_strength: 0.78, creativity_strength: 0.35 } },
  { json: { ...common, slide: 4, template: 'A', fal_prompt: pickFirst(record.slide_4_fal_prompt, buildStoryPrompt(4, record.slide_4_main_text, record.slide_4_sub_text)), main_text: record.slide_4_main_text, sub_text: record.slide_4_sub_text, bg_color: null, reference_image_url: common.source_image_url, reference_strength: 0.75, creativity_strength: 0.42 } },
  { json: { ...common, slide: 5, template: 'A', fal_prompt: pickFirst(record.slide_5_fal_prompt, buildStoryPrompt(5, record.slide_5_main_text, record.slide_5_sub_text)), main_text: record.slide_5_main_text, sub_text: record.slide_5_sub_text, bg_color: null, reference_image_url: common.source_image_url, reference_strength: 0.82, creativity_strength: 0.30 } }
];

const falResults = $input.all();
const slideItems = $('If1').all();

return falResults.map((item, index) => {
  const slide = slideItems[index];

  return {
    json: {
      slide: slide.json.slide,
      template: slide.json.template,
      main_text: slide.json.main_text,
      sub_text: slide.json.sub_text,
      bg_color: slide.json.bg_color,
      shirt_name: slide.json.shirt_name,
      record_id: slide.json.record_id,
      reference_image_url: slide.json.reference_image_url,
      fal_image_url: item.json.images?.[0]?.url || item.json.image?.url || item.json.url || null
    }
  };
});

