const supabaseResults = $input.all();
const slideItems = $('Code in JavaScript8').all();

return slideItems.map((slide, index) => {
  const productImage = supabaseResults[index]?.json?.product_image_url;

  return {
    json: {
      ...slide.json,
      fal_image_url: slide.json.fal_image_url || productImage || null
    }
  };
