const placidItems = $input.all();
const slideItems = $('Sort1').all();
const record = $('Get many rows3').first().json;

const pickFirst = (...values) => values.find((value) => typeof value === 'string' && value.trim() !== '');

const explicitCaption = pickFirst(
  record.caption,
  record.instagram_caption,
  record.instagram_post_caption,
  record.post_caption
);

const productUrl = pickFirst(
  record.shopify_product_url,
  record.product_url,
  record.shop_url,
  record.shop_link
);

const fallbackCaption = [
  record.slide_1_main_text,
  record.slide_2_main_text,
  record.slide_4_main_text,
  productUrl
].filter((value) => typeof value === 'string' && value.trim() !== '').join('\n\n');

const caption = explicitCaption || fallbackCaption;

const getImageUrl = (json) => pickFirst(
  json.image_url,
  json.url,
  json.public_url,
  json.publicUrl,
  json.data?.image_url,
  json.data?.url,
  json.image?.url
);

return placidItems.map((item, index) => {
  const slide = slideItems[index]?.json ?? {};
  const imageUrl = getImageUrl(item.json);

  if (!imageUrl) {
    throw new Error('Missing Placid image URL for slide ' + (slide.slide ?? index + 1));
  }

  return {
    json: {
      slide: slide.slide ?? index + 1,
      record_id: slide.record_id ?? record.id,
      shirt_name: slide.shirt_name ?? record.shirt_name,
      instagram_caption: caption,
      instagram_image_url: imageUrl
    }
  };
});

const containerItems = $input.all();
const instagramItems = $('Prepare Instagram Carousel1').all();
const firstItem = instagramItems[0]?.json;

if (!firstItem) {
  throw new Error('No carousel slides were prepared for Instagram publishing.');
}

const childIds = containerItems
  .map((item) => item.json.id)
  .filter((value) => typeof value === 'string' && value.trim() !== '');

if (childIds.length !== instagramItems.length) {
  throw new Error('Instagram child container creation did not return an id for every slide.');
}

return [
  {
    json: {
      record_id: firstItem.record_id,
      shirt_name: firstItem.shirt_name,
      instagram_caption: firstItem.instagram_caption,
      children: childIds.join(','),
      child_count: childIds.length
    }
  }
];

const carouselContainer = $input.first().json;
const publishPayload = $('Prepare Instagram Carousel Publish1').first().json;

if (!carouselContainer.id) {
  throw new Error('Instagram carousel container was created without an id.');
}

return [
  {
    json: {
      ...publishPayload,
      instagram_creation_id: carouselContainer.id
    }
  }
];

const publishResponse = $input.first().json;
const publishPayload = $('Prepare Instagram Publish1').first().json;

return [{
  json: {
    record_id: publishPayload.record_id,
    shirt_name: publishPayload.shirt_name,
    instagram_post_id: publishResponse.id,
    published_at: new Date().toISOString(),
    status: 'published'
  }
}];
